import React, { useEffect, useState } from "react";
import axios from "axios";
import {
  LineChart,
  Line,
  CartesianGrid,
  XAxis,
  YAxis,
  Tooltip,
  Legend,
  ResponsiveContainer,
} from "recharts";
import "./PriceAnalytics.css";

const API_URL = "http://localhost:7000/api/products";

export default function PriceAnalytics() {
  const [products, setProducts] = useState([]);
  const [filteredData, setFilteredData] = useState([]);
  const [fromDate, setFromDate] = useState("");
  const [toDate, setToDate] = useState("");

  // Fetch product data
  const fetchData = async () => {
    try {
      const res = await axios.get(API_URL);
      const data = Array.isArray(res.data)
        ? res.data
        : res.data.data || [];
      setProducts(data);
      setFilteredData(data);
    } catch (error) {
      console.error("Error fetching data:", error);
    }
  };

  useEffect(() => {
    fetchData();
  }, []);

  // Filter based on date range
  const handleFilter = () => {
    if (!fromDate || !toDate) {
      alert("Please select both dates!");
      return;
    }

    const filtered = products.filter((p) => {
      const created = new Date(p.createdAt);
      return created >= new Date(fromDate) && created <= new Date(toDate);
    });

    setFilteredData(filtered);
  };

  return (
    <div className="analytics-container">
      <h2 className="analytics-title">📈 Product Price & Stock Trends</h2>

      {/* Filter Box */}
      <div className="filter-box">
        <label>From: </label>
        <input
          type="date"
          value={fromDate}
          onChange={(e) => setFromDate(e.target.value)}
        />
        <label>To: </label>
        <input
          type="date"
          value={toDate}
          onChange={(e) => setToDate(e.target.value)}
        />
        <button onClick={handleFilter}>Filter</button>
      </div>

      {/* Graph */}
      <div className="chart-box">
        {filteredData.length > 0 ? (
          <ResponsiveContainer width="100%" height={400}>
            <LineChart data={filteredData}>
              <CartesianGrid strokeDasharray="3 3" />
              <XAxis
                dataKey="name"
                tick={{ fontSize: 12 }}
                interval={0}
                angle={-20}
                textAnchor="end"
              />
              <YAxis />
              <Tooltip />
              <Legend />
              <Line
                type="monotone"
                dataKey="price"
                stroke="#8884d8"
                name="Price (₹)"
                strokeWidth={2}
              />
              <Line
                type="monotone"
                dataKey="stock"
                stroke="#82ca9d"
                name="Stock"
                strokeWidth={2}
              />
            </LineChart>
          </ResponsiveContainer>
        ) : (
          <p className="no-data">No data found for selected range</p>
        )}
      </div>

      {/* Data Table */}
      <div className="product-table">
        <h3>🛒 Filtered Product Data</h3>
        {filteredData.length > 0 ? (
          <table>
            <thead>
              <tr>
                <th>Sr.</th>
                <th>Name</th>
                <th>Category</th>
                <th>Price (₹)</th>
                <th>Stock</th>
                <th>Date</th>
              </tr>
            </thead>
            <tbody>
              {filteredData.map((p, i) => (
                <tr key={p._id}>
                  <td>{i + 1}</td>
                  <td>{p.name}</td>
                  <td>{p.category}</td>
                  <td>{p.price}</td>
                  <td>{p.stock}</td>
                  <td>{new Date(p.createdAt).toLocaleDateString()}</td>
                </tr>
              ))}
            </tbody>
          </table>
        ) : (
          <p style={{ textAlign: "center", marginTop: "20px" }}>
            No products available
          </p>
        )}
      </div>
    </div>
  );
}
